(23, 1, '2026-04-04 02:31:11', '2026-04-04 02:31:11', '<span data-copy-service-computed-style=\"font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 16px; font-weight: 400; margin: 0px; text-decoration: none solid rgb(230, 232, 240); border-bottom: 0px none rgb(230, 232, 240);\">Thắt lưng da thường <!--TgQPHd|[]--></span><mark class=\"HxTRcb\" data-sfc-root=\"c\" data-sfc-cb=\"\" data-copy-service-computed-style=\"font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 16px; font-weight: 500; margin: 0px; text-decoration: none solid rgb(238, 240, 255); border-bottom: 0px none rgb(238, 240, 255);\"><strong>được chế tác từ da bò, da cá sấu cao cấp, đảm bảo độ bền cao, chống nước và chịu nhiệt tốt</strong><!--TgQPHd|[]--></mark>. Sản phẩm có kiểu dáng công sở sang trọng hoặc thời trang với các loại khóa như khóa cài, khóa tự động/trượt. Màu sắc phổ biến là đen hoặc nâu, chiều rộng dây khoảng 3,3cm - 3,5cm, mang lại vẻ lịch lãm và chắc chắn.', 'Thắt lưng da', '', 'publish', 'open', 'closed', '', 'that-lung-da', '', '', '2026-04-04 02:31:11', '2026-04-04 02:31:11', '', 0, 'http://localhost/thienhasagi/?post_type=product&#038;p=23', 0, 'product', '', 0),
(26, 1, '2026-04-04 02:37:27', '2026-04-04 02:37:27', 'Nổi tiếng với sự đa năng, cá tính, jeans phù hợp mọi giới tính/lứa tuổi, thường có 5 túi và màu xanh chàm truyền thống.\r\n\r\nChất liệu: Thường là vải denim (bông dệt chéo), dày dặn, bền bỉ, giữ form tốt.', 'Quần jeans', '', 'publish', 'open', 'closed', '', 'quan-jeans', '', '', '2026-04-04 02:37:53', '2026-04-04 02:37:53', '', 0, 'http://localhost/thienhasagi/?post_type=product&#038;p=26', 0, 'product', '', 0),
(27, 1, '2026-04-04 02:39:24', '2026-04-04 02:39:24', 'Áo có thiết kế hình chữ T đặc trưng, thân suông, tay ngắn, thường làm từ vải cotton co giãn, thoáng mát.', 'Áo phông', '', 'publish', 'open', 'closed', '', 'ao-phong', '', '', '2026-04-04 02:39:24', '2026-04-04 02:39:24', '', 0, 'http://localhost/thienhasagi/?post_type=product&#038;p=27', 0, 'product', '', 0),
(28, 1, '2026-04-04 02:41:07', '2026-04-04 02:41:07', '<span data-copy-service-computed-style=\"font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 16px; font-weight: 400; margin: 0px; text-decoration: none solid rgb(230, 232, 240); border-bottom: 0px none rgb(230, 232, 240);\">Áo khoác mỏng <!--TgQPHd|[]--></span><mark class=\"HxTRcb\" data-sfc-root=\"c\" data-sfc-cb=\"\" data-complete=\"true\" data-sae=\"\" data-copy-service-computed-style=\"font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 16px; font-weight: 500; margin: 0px; text-decoration: none solid rgb(230, 232, 240); border-bottom: 0px none rgb(230, 232, 240);\">là loại trang phục ngoài trời có thiết kế nhẹ, độ dày vừa phải, chủ yếu dùng để che chắn gió, chống nắng hoặc giữ ấm nhẹ trong thời điểm giao mùa<!--TgQPHd|[]--></mark>. Khác với áo khoác mùa đông dày cộm, áo khoác mỏng chú trọng vào sự thoải mái, thoáng khí và tính thời trang.', 'Áo khoác mỏng', '', 'publish', 'open', 'closed', '', 'ao-khoac-mong', '', '', '2026-04-04 02:41:07', '2026-04-04 02:41:07', '', 0, 'http://localhost/thienhasagi/?post_type=product&#038;p=28', 0, 'product', '', 0),
(29, 1, '2026-04-04 02:42:05', '2026-04-04 02:42:05', '<span data-copy-service-computed-style=\"font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 16px; font-weight: 400; margin: 0px; text-decoration: none solid rgb(230, 232, 240); border-bottom: 0px none rgb(230, 232, 240);\">Áo ba lỗ nữ (hay còn gọi là <!--TgQPHd|[]--></span><strong class=\"Yjhzub\" data-sfc-root=\"c\" data-sfc-cb=\"\" data-complete=\"true\" data-processed=\"true\" data-copy-service-computed-style=\"font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 16px; font-weight: 700; margin: 0px; text-decoration: none solid rgb(230, 232, 240); border-bottom: 0px none rgb(230, 232, 240);\">Tank Top<!--TgQPHd|[]--></strong>) <mark class=\"HxTRcb\" data-sfc-root=\"c\" data-sfc-cb=\"\" data-complete=\"true\" data-sae=\"\" data-copy-service-computed-style=\"font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 16px; font-weight: 500; margin: 0px; text-decoration: none solid rgb(230, 232, 240); border-bottom: 0px none rgb(230, 232, 240);\">là mẫu áo không tay, có thiết kế sát nách với phần cổ tròn hoặc khoét sâu, mang lại sự thoải mái và linh hoạt tối đa cho người mặc<!--TgQPHd|[]--></mark>.', 'Áo ba lỗ nữ', '', 'publish', 'open', 'closed', '', 'ao-ba-lo-nu', '', '', '2026-04-04 02:42:05', '2026-04-04 02:42:05', '', 0, 'http://localhost/thienhasagi/?post_type=product&#038;p=29', 0, 'product', '', 0),
