rgin-bottom: 24px !important;\n}\n\n/* 7) Khu vực shop thoáng và giống e-commerce hơn */\n.storefront-breadcrumb {\n    margin-bottom: 20px !important;\n}\n\n.woocommerce-result-count,\n.woocommerce-ordering {\n    margin-bottom: 24px !important;\n}\n\n/* 8) Card sản phẩm đẹp hơn */\nul.products li.product,\n.woocommerce-page ul.products li.product {\n    background: #fff;\n    border: 1px solid #ececec;\n    border-radius: 14px;\n    padding: 16px 16px 20px;\n    box-shadow: 0 6px 18px rgba(0,0,0,0.04);\n    transition: all 0.2s ease;\n}\n\nul.products li.product:hover,\n.woocommerce-page ul.products li.product:hover {\n    transform: translateY(-4px);\n    box-shadow: 0 10px 24px rgba(0,0,0,0.08);\n}\n\n/* 9) Ảnh sản phẩm */\nul.products li.product img,\n.woocommerce-page ul.products li.product img {\n    border-radius: 10px;\n    margin-bottom: 14px !important;\n}\n\n/* 10) Tên sản phẩm */\nul.products li.product h2,\nul.products li.product .woocommerce-loop-product__title,\n.woocommerce-page ul.products li.product h2,\n.woocommerce-page ul.products li.product .woocommerce-loop-product__title {\n    font-size: 18px !important;\n    font-weight: 600 !important;\n    color: #111 !important;\n    min-height: 48px;\n    margin-bottom: 10px !important;\n}\n\n/* 11) Giá sản phẩm */\n.price {\n    color: #c62828 !important;\n    font-weight: 700 !important;\n    font-size: 18px !important;\n}\n\n.price del {\n    color: #999 !important;\n    font-size: 14px !important;\n}\n\n.price ins {\n    background: transparent !important;\n}\n\n/* 12) Nút Add to cart nhìn thương mại hơn */\n.button,\nbutton,\ninput[type=\"button\"],\ninput[type=\"submit\"],\na.button,\n.added_to_cart,\n.single_add_to_cart_button,\n.checkout-button,\n.wc-forward {\n    background: #111 !important;\n    color: #fff !important;\n    border-radius: 10px !important;\n    border: none !important;\n    padding: 12px 18px !important;\n    font-weight: 600 !important;\n    transition: all 0.2s ease;\n}\n\n.button:hover,\nbutton:hover,\ninput[type=\"button\"]:hover,\ninput[type=\"submit\"]:hover,\na.button:hover,\n.added_to_cart:hover,\n.single_add_to_cart_button:hover,\n.checkout-button:hover,\n.wc-forward:hover {\n    background: #c62828 !important;\n    color: #fff !important;\n}\n\n/* 13) Sale badge đẹp hơn */\n.onsale {\n    background: #c62828 !important;\n    color: #fff !important;\n    border-radius: 999px !important;\n    padding: 6px 10px !important;\n    font-size: 12px !important;\n    font-weight: 700 !important;\n    min-width: auto !important;\n    min-height: auto !important;\n    line-height: 1.2 !important;\n    box-shadow: none !important;\n}\n\n/* 14) Cart / Checkout box đẹp hơn */\n.woocommerce-cart-form,\n.cart-collaterals,\n.woocommerce-checkout-review-order,\n.woocommerce-billing-fields,\n.woocommerce-additional-fields,\n.woocommerce-form-coupon,\n.woocommerce-MyAccount-content,\n.woocommerce-Address,\n.woocommerce-orders-table {\n    background: #fff;\n    border: 1px solid #ececec;\n    border-radius: 14px;\n    padding: 20px;\n    box-shadow: 0 6px 18px rgba(0,0,0,0.04);\n}\n\n/* 15) Form input đẹp hơn */\ninput[type=\"text\"],\ninput[type=\"email\"],\ninput[type=\"tel\"],\ninput[type=\"password\"],\ninput[type=\"search\"],\ntextarea,\nselect {\n    border: 1px solid #dcdcdc !important;\n    border-radius: 10px !important;\n    background: #fff !important;\n    padding: 12px 14px !important;\n}\n\n/* 16) Footer nhìn như doanh nghiệp hơn */\n.site-footer {\n    background: #111 !important;\n    color: #eee !important;\n    padding-top: 40px !important;\n    padding-bottom: 20px !important;\n    margin-top: 40px !important;\n}\n\n.site-footer,\n.site-footer a,\n.site-footer .widget-title {\n    color: #eee !important;\n}\n\n.site-footer a:hover {\n    color: #ffb3b3 !important;\n}\n\n.site-footer .widget {\n    margin-bottom: 20px;\n}\n\n.site-footer .widget-title {\n    font-size: 18px !important;\n    font-weight: 700 !important;\n    margin-bottom: 14px !important;\n}\n\n.site-info {\n    border-top: 1px solid rgba(255,255,255,0.12);\n    padding-top: 14px;\n    margin-top: 20px;\n    text-align: center;\n    color: #ccc !important;\n}\n\n/* 17) Ẩn một số chi tiết thừa nếu có */\n.storefront-handheld-footer-bar {\n    display: none;\n}\n\n/* 18) Responsive */\n@media (max-width: 768px) {\n    .site-title a {\n        font-size: 28px !important;\n    }\n\n    .page-title,\n    .woocommerce-products-header__title.page-title {\n        font-size: 32px !important;\n    }\n\n    ul.products li.product,\n    .woocommerce-page ul.products li.product {\n        padding: 12px;\n    }\n}\n/* FIX FOOTER TEXT COLOR */\n.site-footer,\n.site-footer p,\n.site-footer h4,\n.site-footer span,\n.site-footer a {\n    color: #ffffff !important;\n}\n\n.site-footer a:hover {\n    color: #ffb3b3 !important;\n}\n/* ===== VIET HOA WOOCOMMERCE ===== */\n\n/* SHOP TITLE */\n.woocommerce-products-header__title.page-title {\n    font-size: 0;\n}\n\n/* SORTING */\n.woocommerce-ordering select {\n    font-size: 0;\n}\n.woocommerce-ordering:before {\n    content: \"Sắp xếp:\";\n    font-weight: 600;\n    margin-right: 10px;\n}\n\n/* RESULT COUNT */\n.woocommerce-result-count {\n    font-size: 0;\n}\n.woocommerce-result-count:after {\n    content: \"Hiển thị tất cả sản phẩm\";\n    font-size: 14px;\n    color: #666;\n}\n\n/* SALE BADGE */\n.onsale {\n    font-size: 0 !important;\n}\n.onsale:after {\n    content: \"GIẢM GIÁ\";\n    font-size: 12px;\n}\n\n/* ADD TO CART BUTTON */\n.add_to_cart_button,\n.button.product_type_simple {\n    font-size: 0 !important;\n}\n.add_to_cart_button:after,\n.button.product_type_simple:after {\n    content: \"Thêm vào giỏ\";\n    font-size: 14px;\n}\n\n/* SEARCH */\n.site-search input::placeholder {\n    content: \"Tìm sản phẩm...\";\n}\n\n/* BREADCRUMB */\n.woocommerce-breadcrumb {\n    font-size: 0;\n}\n.woocommerce-breadcrumb:after {\n    content: \"Trang chủ / Cửa hàng\";\n    font-size: 14px;\n}\n\n/* CART TEXT */\n.site-header-cart .cart-contents {\n    font-size: 0;\n}\n.site-header-cart .cart-contents:after {\n    content: \"Giỏ hàng\";\n    font-size: 14px;\n}\n/* FIX NUT THEM VAO GIO BI MAT CHU */\nul.products li.product .button,\n.woocommerce ul.products li.product .button,\n.add_to_cart_button,\n.button.product_type_simple {\n    font-size: 14px !important;\n    line-height: 1.2 !important;\n    color: #fff !important;\n    text-indent: 0 !important;\n    overflow: visible !important;\n    white-space: nowrap !important;\n    min-width: 140px !important;\n    text-align: center !important;\n}\n\nul.products li.product .button::after,\n.woocommerce ul.products li.product .button::after,\n.add_to_cart_button::after,\n.button.product_type_simple::after {\n    content: none !important;\n}\n/* FIX NUT ADD TO CART -> THÊM VÀO GIỎ HÀNG */\nul.products li.product .button,\n.woocommerce ul.products li.product .button,\n.add_to_cart_button,\n.button.product_type_simple {\n    position: relative;\n    font-size: 0 !important;\n    min-width: 160px !important;\n    text-align: center !important;\n    color: transparent !important;\n}\n\nul.products li.product .button::before,\n.woocommerce ul.products li.product .button::before,\n.add_to_cart_button::before,\n.button.product_type_simple::before {\n    content: \"Thêm vào giỏ hàng\";\n    font-size: 14px;\n    line-height: 1.2;\n    color: #fff;\n    position: relative;\n    z-index: 2;\n}', 'storefront', '', 'inherit', 'closed', 'closed', '', '33-revision-v1', '', '', '2026-04-04 03:32:40', '2026-04-04 03:32:40', '', 33, 'http://localhost/thienhasagi/?p=53', 0, 'revision', '', 0),
