(66, 1, '2026-06-05 14:23:40', '2026-06-05 14:23:40', '{\n    \"custom_css[storefront]\": {\n        \"value\": \"/* B\\u1ecf sidebar WooCommerce */\\n#secondary {\\n    display: none;\\n}\\n\\n/* Cho n\\u1ed9i dung full width */\\n#primary {\\n    width: 100% !important;\\n}\\n/* ===== THIEN STORE - COMMERCIAL LOOK ===== */\\n\\n/* 1) \\u1ea8n sidebar \\u0111\\u1ec3 shop full width */\\n#secondary {\\n    display: none !important;\\n}\\n\\n#primary,\\n.content-area {\\n    width: 100% !important;\\n    float: none !important;\\n    margin: 0 !important;\\n}\\n\\n/* 2) T\\u1ed5ng th\\u1ec3 trang g\\u1ecdn h\\u01a1n */\\nbody {\\n    background: #f7f7f7;\\n}\\n\\n.site {\\n    background: #ffffff;\\n}\\n\\n.site-main {\\n    padding-top: 10px;\\n    padding-bottom: 30px;\\n}\\n\\n/* 3) Header g\\u1ecdn, s\\u1ea1ch, gi\\u1ed1ng web b\\u00e1n h\\u00e0ng h\\u01a1n */\\n.site-header {\\n    background: #ffffff !important;\\n    border-bottom: 1px solid #e5e5e5;\\n    padding-top: 16px;\\n    padding-bottom: 10px;\\n    margin-bottom: 24px;\\n}\\n\\n.site-branding {\\n    margin-bottom: 10px !important;\\n}\\n\\n.site-title a {\\n    font-size: 34px !important;\\n    font-weight: 700 !important;\\n    color: #111 !important;\\n    text-decoration: none !important;\\n}\\n\\n.site-description {\\n    display: none !important;\\n}\\n\\n/* 4) Menu \\u0111\\u1eb9p v\\u00e0 g\\u1ecdn h\\u01a1n */\\n.main-navigation ul.menu > li > a,\\n.main-navigation ul.nav-menu > li > a {\\n    font-weight: 600;\\n    font-size: 15px;\\n    color: #222 !important;\\n    padding: 12px 14px !important;\\n}\\n\\n.main-navigation ul.menu > li > a:hover,\\n.main-navigation ul.nav-menu > li > a:hover {\\n    color: #c62828 !important;\\n}\\n\\n/* 5) \\u00d4 t\\u00ecm ki\\u1ebfm v\\u00e0 gi\\u1ecf h\\u00e0ng g\\u1ecdn h\\u01a1n */\\n.site-search .widget_product_search,\\n.site-search .widget_search {\\n    margin-bottom: 0 !important;\\n}\\n\\n.site-search input[type=\\\"search\\\"] {\\n    border: 1px solid #ddd;\\n    border-radius: 8px;\\n    background: #fff;\\n}\\n\\n.site-header-cart .cart-contents {\\n    font-weight: 600;\\n}\\n\\n/* 6) Ti\\u00eau \\u0111\\u1ec1 trang */\\n.page-title,\\n.woocommerce-products-header__title.page-title {\\n    font-size: 42px !important;\\n    font-weight: 700 !important;\\n    color: #111;\\n    margin-bottom: 24px !important;\\n}\\n\\n/* 7) Khu v\\u1ef1c shop tho\\u00e1ng v\\u00e0 gi\\u1ed1ng e-commerce h\\u01a1n */\\n.storefront-breadcrumb {\\n    margin-bottom: 20px !important;\\n}\\n\\n.woocommerce-result-count,\\n.woocommerce-ordering {\\n    margin-bottom: 24px !important;\\n}\\n\\n/* 8) Card s\\u1ea3n ph\\u1ea9m \\u0111\\u1eb9p h\\u01a1n */\\nul.products li.product,\\n.woocommerce-page ul.products li.product {\\n    background: #fff;\\n    border: 1px solid #ececec;\\n    border-radius: 14px;\\n    padding: 16px 16px 20px;\\n    box-shadow: 0 6px 18px rgba(0,0,0,0.04);\\n    transition: all 0.2s ease;\\n}\\n\\nul.products li.product:hover,\\n.woocommerce-page ul.products li.product:hover {\\n    transform: translateY(-4px);\\n    box-shadow: 0 10px 24px rgba(0,0,0,0.08);\\n}\\n\\n/* 9) \\u1ea2nh s\\u1ea3n ph\\u1ea9m */\\nul.products li.product img,\\n.woocommerce-page ul.products li.product img {\\n    border-radius: 10px;\\n    margin-bottom: 14px !important;\\n}\\n\\n/* 10) T\\u00ean s\\u1ea3n ph\\u1ea9m */\\nul.products li.product h2,\\nul.products li.product .woocommerce-loop-product__title,\\n.woocommerce-page ul.products li.product h2,\\n.woocommerce-page ul.products li.product .woocommerce-loop-product__title {\\n    font-size: 18px !important;\\n    font-weight: 600 !important;\\n    color: #111 !important;\\n    min-height: 48px;\\n    margin-bottom: 10px !important;\\n}\\n\\n/* 11) Gi\\u00e1 s\\u1ea3n ph\\u1ea9m */\\n.price {\\n    color: #c62828 !important;\\n    font-weight: 700 !important;\\n    font-size: 18px !important;\\n}\\n\\n.price del {\\n    color: #999 !important;\\n    font-size: 14px !important;\\n}\\n\\n.price ins {\\n    background: transparent !important;\\n}\\n\\n/* 12) N\\u00fat Add to cart nh\\u00ecn th\\u01b0\\u01a1ng m\\u1ea1i h\\u01a1n */\\n.button,\\nbutton,\\ninput[type=\\\"button\\\"],\\ninput[type=\\\"submit\\\"],\\na.button,\\n.added_to_cart,\\n.single_add_to_cart_button,\\n.checkout-button,\\n.wc-forward {\\n    background: #111 !important;\\n    color: #fff !important;\\n    border-radius: 10px !important;\\n    border: none !important;\\n    padding: 12px 18px !important;\\n    font-weight: 600 !important;\\n    transition: all 0.2s ease;\\n}\\n\\n.button:hover,\\nbutton:hover,\\ninput[type=\\\"button\\\"]:hover,\\ninput[type=\\\"submit\\\"]:hover,\\na.button:hover,\\n.added_to_cart:hover,\\n.single_add_to_cart_button:hover,\\n.checkout-button:hover,\\n.wc-forward:hover {\\n    background: #c62828 !important;\\n    color: #fff !important;\\n}\\n\\n/* 13) Sale badge \\u0111\\u1eb9p h\\u01a1n */\\n.onsale {\\n    background: #c62828 !important;\\n    color: #fff !important;\\n    border-radius: 999px !important;\\n    padding: 6px 10px !important;\\n    font-size: 12px !important;\\n    font-weight: 700 !important;\\n    min-width: auto !important;\\n    min-height: auto !important;\\n    line-height: 1.2 !important;\\n    box-shadow: none !important;\\n}\\n\\n/* 14) Cart / Checkout box \\u0111\\u1eb9p h\\u01a1n */\\n.woocommerce-cart-form,\\n.cart-collaterals,\\n.woocommerce-checkout-review-order,\\n.woocommerce-billing-fields,\\n.woocommerce-additional-fields,\\n.woocommerce-form-coupon,\\n.woocommerce-MyAccount-content,\\n.woocommerce-Address,\\n.woocommerce-orders-table {\\n    background: #fff;\\n    border: 1px solid #ececec;\\n    border-radius: 14px;\\n    padding: 20px;\\n    box-shadow: 0 6px 18px rgba(0,0,0,0.04);\\n}\\n\\n/* 15) Form input \\u0111\\u1eb9p h\\u01a1n */\\ninput[type=\\\"text\\\"],\\ninput[type=\\\"email\\\"],\\ninput[type=\\\"tel\\\"],\\ninput[type=\\\"password\\\"],\\ninput[type=\\\"search\\\"],\\ntextarea,\\nselect {\\n    border: 1px solid #dcdcdc !important;\\n    border-radius: 10px !important;\\n    background: #fff !important;\\n    padding: 12px 14px !important;\\n}\\n\\n/* 16) Footer nh\\u00ecn nh\\u01b0 doanh nghi\\u1ec7p h\\u01a1n */\\n.site-footer {\\n    background: #111 !important;\\n    color: #eee !important;\\n    padding-top: 40px !important;\\n    padding-bottom: 20px !important;\\n    margin-top: 40px !important;\\n}\\n\\n.site-footer,\\n.site-footer a,\\n.site-footer .widget-title {\\n    color: #eee !important;\\n}\\n\\n.site-footer a:hover {\\n    color: #ffb3b3 !important;\\n}\\n\\n.site-footer .widget {\\n    margin-bottom: 20px;\\n}\\n\\n.site-footer .widget-title {\\n    font-size: 18px !important;\\n    font-weight: 700 !important;\\n    margin-bottom: 14px !important;\\n}\\n\\n.site-info {\\n    border-top: 1px solid rgba(255,255,255,0.12);\\n    padding-top: 14px;\\n    margin-top: 20px;\\n    text-align: center;\\n    color: #ccc !important;\\n}\\n\\n/* 17) \\u1ea8n m\\u1ed9t s\\u1ed1 chi ti\\u1ebft th\\u1eeba n\\u1ebfu c\\u00f3 */\\n.storefront-handheld-footer-bar {\\n    display: none;\\n}\\n\\n/* 18) Responsive */\\n@media (max-width: 768px) {\\n    .site-title a {\\n        font-size: 28px !important;\\n    }\\n\\n    .page-title,\\n    .woocommerce-products-header__title.page-title {\\n        font-size: 32px !important;\\n    }\\n\\n    ul.products li.product,\\n    .woocommerce-page ul.products li.product {\\n        padding: 12px;\\n    }\\n}\\n/* FIX FOOTER TEXT COLOR */\\n.site-footer,\\n.site-footer p,\\n.site-footer h4,\\n.site-footer span,\\n.site-footer a {\\n    color: #ffffff !important;\\n}\\n\\n.site-footer a:hover {\\n    color: #ffb3b3 !important;\\n}\\n/* ===== VIET HOA WOOCOMMERCE ===== */\\n\\n/* SHOP TITLE */\\n.woocommerce-products-header__title.page-title {\\n    font-size: 0;\\n}\\n\\n/* SORTING */\\n.woocommerce-ordering select {\\n    font-size: 0;\\n}\\n.woocommerce-ordering:before {\\n    content: \\\"S\\u1eafp x\\u1ebfp:\\\";\\n    font-weight: 600;\\n    margin-right: 10px;\\n}\\n\\n/* RESULT COUNT */\\n.woocommerce-result-count {\\n    font-size: 0;\\n}\\n.woocommerce-result-count:after {\\n    content: \\\"Hi\\u1ec3n th\\u1ecb t\\u1ea5t c\\u1ea3 s\\u1ea3n ph\\u1ea9m\\\";\\n    font-size: 14px;\\n    color: #666;\\n}\\n\\n/* SALE BADGE */\\n.onsale {\\n    font-size: 0 !important;\\n}\\n.onsale:after {\\n    content: \\\"GI\\u1ea2M GI\\u00c1\\\";\\n    font-size: 12px;\\n}\\n\\n/* ADD TO CART BUTTON */\\n.add_to_cart_button,\\n.button.product_type_simple {\\n    font-size: 0 !important;\\n}\\n.add_to_cart_button:after,\\n.button.product_type_simple:after {\\n    content: \\\"Th\\u00eam v\\u00e0o gi\\u1ecf\\\";\\n    font-size: 14px;\\n}\\n\\n/* SEARCH */\\n.site-search input::placeholder {\\n    content: \\\"T\\u00ecm s\\u1ea3n ph\\u1ea9m...\\\";\\n}\\n\\n/* BREADCRUMB */\\n.woocommerce-breadcrumb {\\n    font-size: 0;\\n}\\n.woocommerce-breadcrumb:after {\\n    content: \\\"Trang ch\\u1ee7 / C\\u1eeda h\\u00e0ng\\\";\\n    font-size: 14px;\\n}\\n\\n/* CART TEXT */\\n.site-header-cart .cart-contents {\\n    font-size: 0;\\n}\\n.site-header-cart .cart-contents:after {\\n    content: \\\"Gi\\u1ecf h\\u00e0ng\\\";\\n    font-size: 14px;\\n}\\n/* FIX NUT THEM VAO GIO BI MAT CHU */\\nul.products li.product .button,\\n.woocommerce ul.products li.product .button,\\n.add_to_cart_button,\\n.button.product_type_simple {\\n    font-size: 14px !important;\\n    line-height: 1.2 !important;\\n    color: #fff !important;\\n    text-indent: 0 !important;\\n    overflow: visible !important;\\n    white-space: nowrap !important;\\n    min-width: 140px !important;\\n    text-align: center !important;\\n}\\n\\nul.products li.product .button::after,\\n.woocommerce ul.products li.product .button::after,\\n.add_to_cart_button::after,\\n.button.product_type_simple::after {\\n    content: none !important;\\n}\\n/* FIX NUT ADD TO CART -> TH\\u00caM V\\u00c0O GI\\u1ece H\\u00c0NG */\\nul.products li.product .button,\\n.woocommerce ul.products li.product .button,\\n.add_to_cart_button,\\n.button.product_type_simple {\\n    position: relative;\\n    font-size: 0 !important;\\n    min-width: 160px !important;\\n    text-align: center !important;\\n    color: transparent !important;\\n}\\n\\nul.products li.product .button::before,\\n.woocommerce ul.products li.product .button::before,\\n.add_to_cart_button::before,\\n.button.product_type_simple::before {\\n    content: \\\"Th\\u00eam v\\u00e0o gi\\u1ecf h\\u00e0ng\\\";\\n    font-size: 14px;\\n    line-height: 1.2;\\n    color: #fff;\\n    position: relative;\\n    z-index: 2;\\n}\\n/* VIET HOA NUT VIEW CART */\\n.added_to_cart.wc-forward {\\n    position: relative;\\n    font-size: 0 !important;\\n    color: transparent !important;\\n    min-width: 120px !important;\\n    text-align: center !important;\\n}\\n\\n.added_to_cart.wc-forward::before {\\n    content: \\\"Xem gi\\u1ecf h\\u00e0ng\\\";\\n    font-size: 14px;\\n    line-height: 1.2;\\n    color: #fff;\\n    position: relative;\\n    z-index: 2;\\n}\\n.woocommerce-breadcrumb {\\n    font-size: 0;\\n}\\n.woocommerce-breadcrumb:after {\\n    content: \\\"Trang ch\\u1ee7 / C\\u1eeda h\\u00e0ng\\\";\\n    font-size: 14px;\\n}\\n/* ===== Thi\\u1ec7n store - AI Chatbox Custom UI ===== */\\n\\n/* N\\u00fat bong b\\u00f3ng chat */\\n.mwai-open-button,\\n.mwai-chatbot-button,\\n.mwai-trigger,\\n.mwai-window .mwai-open-button {\\n    width: 64px !important;\\n    height: 64px !important;\\n    border-radius: 50% !important;\\n    background: #111111 !important;\\n    color: #ffffff !important;\\n    box-shadow: 0 12px 35px rgba(0, 0, 0, 0.22) !important;\\n    border: 2px solid #ffffff !important;\\n    transition: all 0.25s ease !important;\\n}\\n\\n.mwai-open-button:hover,\\n.mwai-chatbot-button:hover,\\n.mwai-trigger:hover {\\n    transform: translateY(-4px) scale(1.04) !important;\\n    background: #d32f2f !important;\\n    box-shadow: 0 16px 40px rgba(211, 47, 47, 0.35) !important;\\n}\\n\\n/* Khung chatbot */\\n.mwai-chatbot,\\n.mwai-window,\\n.mwai-chat {\\n    border-radius: 22px !important;\\n    overflow: hidden !important;\\n    border: 1px solid #eeeeee !important;\\n    box-shadow: 0 24px 70px rgba(0, 0, 0, 0.18) !important;\\n    font-family: inherit !important;\\n}\\n\\n/* Header chatbot */\\n.mwai-header {\\n    background: linear-gradient(135deg, #111111, #2a2a2a) !important;\\n    color: #ffffff !important;\\n    padding: 18px 20px !important;\\n    border-bottom: none !important;\\n}\\n\\n.mwai-header .mwai-title,\\n.mwai-header h2,\\n.mwai-header h3 {\\n    color: #ffffff !important;\\n    font-size: 17px !important;\\n    font-weight: 700 !important;\\n    letter-spacing: 0.2px !important;\\n}\\n\\n/* Khu v\\u1ef1c h\\u1ed9i tho\\u1ea1i */\\n.mwai-conversation,\\n.mwai-messages {\\n    background: #fafafa !important;\\n    padding: 18px !important;\\n}\\n\\n/* Tin nh\\u1eafn chung */\\n.mwai-reply,\\n.mwai-message {\\n    margin-bottom: 12px !important;\\n}\\n\\n/* Tin nh\\u1eafn AI */\\n.mwai-ai .mwai-text,\\n.mwai-reply.mwai-ai,\\n.mwai-message.mwai-ai {\\n    background: #ffffff !important;\\n    color: #222222 !important;\\n    border: 1px solid #eeeeee !important;\\n    border-radius: 16px 16px 16px 6px !important;\\n    padding: 12px 14px !important;\\n    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.04) !important;\\n}\\n\\n/* Tin nh\\u1eafn ng\\u01b0\\u1eddi d\\u00f9ng */\\n.mwai-user .mwai-text,\\n.mwai-reply.mwai-user,\\n.mwai-message.mwai-user {\\n    background: #111111 !important;\\n    color: #ffffff !important;\\n    border-radius: 16px 16px 6px 16px !important;\\n    padding: 12px 14px !important;\\n}\\n\\n/* \\u00d4 nh\\u1eadp tin nh\\u1eafn */\\n.mwai-input,\\n.mwai-input textarea,\\n.mwai-input input {\\n    background: #ffffff !important;\\n    border-top: 1px solid #eeeeee !important;\\n}\\n\\n.mwai-input textarea,\\n.mwai-input input[type=\\\"text\\\"] {\\n    border: 1px solid #dddddd !important;\\n    border-radius: 999px !important;\\n    padding: 13px 48px 13px 16px !important;\\n    font-size: 14px !important;\\n    outline: none !important;\\n    background: #ffffff !important;\\n    color: #111111 !important;\\n}\\n\\n.mwai-input textarea:focus,\\n.mwai-input input[type=\\\"text\\\"]:focus {\\n    border-color: #111111 !important;\\n    box-shadow: 0 0 0 3px rgba(17, 17, 17, 0.08) !important;\\n}\\n\\n/* N\\u00fat g\\u1eedi */\\n.mwai-input button,\\n.mwai-send {\\n    background: #111111 !important;\\n    color: #ffffff !important;\\n    border-radius: 999px !important;\\n    border: none !important;\\n    transition: all 0.2s ease !important;\\n}\\n\\n.mwai-input button:hover,\\n.mwai-send:hover {\\n    background: #d32f2f !important;\\n    transform: scale(1.04) !important;\\n}\\n\\n/* Text nh\\u1ecf / powered by n\\u1ebfu c\\u00f3 */\\n.mwai-footer,\\n.mwai-compliance,\\n.mwai-powered {\\n    font-size: 11px !important;\\n    color: #999999 !important;\\n    background: #ffffff !important;\\n}\\n\\n/* Mobile */\\n@media (max-width: 768px) {\\n    .mwai-chatbot,\\n    .mwai-window,\\n    .mwai-chat {\\n        width: calc(100vw - 24px) !important;\\n        right: 12px !important;\\n        left: 12px !important;\\n        bottom: 90px !important;\\n        border-radius: 20px !important;\\n    }\\n\\n    .mwai-open-button,\\n    .mwai-chatbot-button,\\n    .mwai-trigger {\\n        width: 58px !important;\\n        height: 58px !important;\\n        right: 18px !important;\\n        bottom: 18px !important;\\n    }\\n}\",\n        \"type\": \"custom_css\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-05 14:23:40\"\n    }\n}', '', '', 'trash', 'closed', 'closed', '', '8bd3e42b-9078-4358-815e-3afd0fa19015', '', '', '2026-06-05 14:23:40', '2026-06-05 14:23:40', '', 0, 'http://localhost/thienhasagi/index.php/2026/06/05/8bd3e42b-9078-4358-815e-3afd0fa19015/', 0, 'customize_changeset', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(67, 1, '2026-06-05 14:23:40', '2026-06-05 14:23:40', '/* Bỏ sidebar WooCommerce */\n#secondary {\n    display: none;\n}\n\n/* Cho nội dung full width */\n#primary {\n    width: 100% !important;\n}\n/* ===== THIEN STORE - COMMERCIAL LOOK ===== */\n\n/* 1) Ẩn sidebar để shop full width */\n#secondary {\n    display: none !important;\n}\n\n#primary,\n.content-area {\n    width: 100% !important;\n    float: none !important;\n    margin: 0 !important;\n}\n\n/* 2) Tổng thể trang gọn hơn */\nbody {\n    background: #f7f7f7;\n}\n\n.site {\n    background: #ffffff;\n}\n\n.site-main {\n    padding-top: 10px;\n    padding-bottom: 30px;\n}\n\n/* 3) Header gọn, sạch, giống web bán hàng hơn */\n.site-header {\n    background: #ffffff !important;\n    border-bottom: 1px solid #e5e5e5;\n    padding-top: 16px;\n    padding-bottom: 10px;\n    margin-bottom: 24px;\n}\n\n.site-branding {\n    margin-bottom: 10px !important;\n}\n\n.site-title a {\n    font-size: 34px !important;\n    font-weight: 700 !important;\n    color: #111 !important;\n    text-decoration: none !important;\n}\n\n.site-description {\n    display: none !important;\n}\n\n/* 4) Menu đẹp và gọn hơn */\n.main-navigation ul.menu > li > a,\n.main-navigation ul.nav-menu > li > a {\n    font-weight: 600;\n    font-size: 15px;\n    color: #222 !important;\n    padding: 12px 14px !important;\n}\n\n.main-navigation ul.menu > li > a:hover,\n.main-navigation ul.nav-menu > li > a:hover {\n    color: #c62828 !important;\n}\n\n/* 5) Ô tìm kiếm và giỏ hàng gọn hơn */\n.site-search .widget_product_search,\n.site-search .widget_search {\n    margin-bottom: 0 !important;\n}\n\n.site-search input[type=\"search\"] {\n    border: 1px solid #ddd;\n    border-radius: 8px;\n    background: #fff;\n}\n\n.site-header-cart .cart-contents {\n    font-weight: 600;\n}\n\n/* 6) Tiêu đề trang */\n.page-title,\n.woocommerce-products-header__title.page-title {\n    font-size: 42px !important;\n    font-weight: 700 !important;\n    color: #111;\n    margin-bottom: 24px !important;\n}\n\n/* 7) Khu vực shop thoáng và giống e-commerce hơn */\n.storefront-breadcrumb {\n    margin-bottom: 20px !important;\n}\n\n.woocommerce-result-count,\n.woocommerce-ordering {\n    margin-bottom: 24px !important;\n}\n\n/* 8) Card sản phẩm đẹp hơn */\nul.products li.product,\n.woocommerce-page ul.products li.product {\n    background: #fff;\n    border: 1px solid #ececec;\n    border-radius: 14px;\n    padding: 16px 16px 20px;\n    box-shadow: 0 6px 18px rgba(0,0,0,0.04);\n    transition: all 0.2s ease;\n}\n\nul.products li.product:hover,\n.woocommerce-page ul.products li.product:hover {\n    transform: translateY(-4px);\n    box-shadow: 0 10px 24px rgba(0,0,0,0.08);\n}\n\n/* 9) Ảnh sản phẩm */\nul.products li.product img,\n.woocommerce-page ul.products li.product img {\n    border-radius: 10px;\n    margin-bottom: 14px !important;\n}\n\n/* 10) Tên sản phẩm */\nul.products li.product h2,\nul.products li.product .woocommerce-loop-product__title,\n.woocommerce-page ul.products li.product h2,\n.woocommerce-page ul.products li.product .woocommerce-loop-product__title {\n    font-size: 18px !important;\n    font-weight: 600 !important;\n    color: #111 !important;\n    min-height: 48px;\n    margin-bottom: 10px !important;\n}\n\n/* 11) Giá sản phẩm */\n.price {\n    color: #c62828 !important;\n    font-weight: 700 !important;\n    font-size: 18px !important;\n}\n\n.price del {\n    color: #999 !important;\n    font-size: 14px !important;\n}\n\n.price ins {\n    background: transparent !important;\n}\n\n/* 12) Nút Add to cart nhìn thương mại hơn */\n.button,\nbutton,\ninput[type=\"button\"],\ninput[type=\"submit\"],\na.button,\n.added_to_cart,\n.single_add_to_cart_button,\n.checkout-button,\n.wc-forward {\n    background: #111 !important;\n    color: #fff !important;\n    border-radius: 10px !important;\n    border: none !important;\n    padding: 12px 18px !important;\n    font-weight: 600 !important;\n    transition: all 0.2s ease;\n}\n\n.button:hover,\nbutton:hover,\ninput[type=\"button\"]:hover,\ninput[type=\"submit\"]:hover,\na.button:hover,\n.added_to_cart:hover,\n.single_add_to_cart_button:hover,\n.checkout-button:hover,\n.wc-forward:hover {\n    background: #c62828 !important;\n    color: #fff !important;\n}\n\n/* 13) Sale badge đẹp hơn */\n.onsale {\n    background: #c62828 !important;\n    color: #fff !important;\n    border-radius: 999px !important;\n    padding: 6px 10px !important;\n    font-size: 12px !important;\n    font-weight: 700 !important;\n    min-width: auto !important;\n    min-height: auto !important;\n    line-height: 1.2 !important;\n    box-shadow: none !important;\n}\n\n/* 14) Cart / Checkout box đẹp hơn */\n.woocommerce-cart-form,\n.cart-collaterals,\n.woocommerce-checkout-review-order,\n.woocommerce-billing-fields,\n.woocommerce-additional-fields,\n.woocommerce-form-coupon,\n.woocommerce-MyAccount-content,\n.woocommerce-Address,\n.woocommerce-orders-table {\n    background: #fff;\n    border: 1px solid #ececec;\n    border-radius: 14px;\n    padding: 20px;\n    box-shadow: 0 6px 18px rgba(0,0,0,0.04);\n}\n\n/* 15) Form input đẹp hơn */\ninput[type=\"text\"],\ninput[type=\"email\"],\ninput[type=\"tel\"],\ninput[type=\"password\"],\ninput[type=\"search\"],\ntextarea,\nselect {\n    border: 1px solid #dcdcdc !important;\n    border-radius: 10px !important;\n    background: #fff !important;\n    padding: 12px 14px !important;\n}\n\n/* 16) Footer nhìn như doanh nghiệp hơn */\n.site-footer {\n    background: #111 !important;\n    color: #eee !important;\n    padding-top: 40px !important;\n    padding-bottom: 20px !important;\n    margin-top: 40px !important;\n}\n\n.site-footer,\n.site-footer a,\n.site-footer .widget-title {\n    color: #eee !important;\n}\n\n.site-footer a:hover {\n    color: #ffb3b3 !important;\n}\n\n.site-footer .widget {\n    margin-bottom: 20px;\n}\n\n.site-footer .widget-title {\n    font-size: 18px !important;\n    font-weight: 700 !important;\n    margin-bottom: 14px !important;\n}\n\n.site-info {\n    border-top: 1px solid rgba(255,255,255,0.12);\n    padding-top: 14px;\n    margin-top: 20px;\n    text-align: center;\n    color: #ccc !important;\n}\n\n/* 17) Ẩn một số chi tiết thừa nếu có */\n.storefront-handheld-footer-bar {\n    display: none;\n}\n\n/* 18) Responsive */\n@media (max-width: 768px) {\n    .site-title a {\n        font-size: 28px !important;\n    }\n\n    .page-title,\n    .woocommerce-products-header__title.page-title {\n        font-size: 32px !important;\n    }\n\n    ul.products li.product,\n    .woocommerce-page ul.products li.product {\n        padding: 12px;\n    }\n}\n/* FIX FOOTER TEXT COLOR */\n.site-footer,\n.site-footer p,\n.site-footer h4,\n.site-footer span,\n.site-footer a {\n    color: #ffffff !important;\n}\n\n.site-footer a:hover {\n    color: #ffb3b3 !important;\n}\n/* ===== VIET HOA WOOCOMMERCE ===== */\n\n/* SHOP TITLE */\n.woocommerce-products-header__title.page-title {\n    font-size: 0;\n}\n\n/* SORTING */\n.woocommerce-ordering select {\n    font-size: 0;\n}\n.woocommerce-ordering:before {\n    content: \"Sắp xếp:\";\n    font-weight: 600;\n    margin-right: 10px;\n}\n\n/* RESULT COUNT */\n.woocommerce-result-count {\n    font-size: 0;\n}\n.woocommerce-result-count:after {\n    content: \"Hiển thị tất cả sản phẩm\";\n    font-size: 14px;\n    color: #666;\n}\n\n/* SALE BADGE */\n.onsale {\n    font-size: 0 !important;\n}\n.onsale:after {\n    content: \"GIẢM GIÁ\";\n    font-size: 12px;\n}\n\n/* ADD TO CART BUTTON */\n.add_to_cart_button,\n.button.product_type_simple {\n    font-size: 0 !important;\n}\n.add_to_cart_button:after,\n.button.product_type_simple:after {\n    content: \"Thêm vào giỏ\";\n    font-size: 14px;\n}\n\n/* SEARCH */\n.site-search input::placeholder {\n    content: \"Tìm sản phẩm...\";\n}\n\n/* BREADCRUMB */\n.woocommerce-breadcrumb {\n    font-size: 0;\n}\n.woocommerce-breadcrumb:after {\n    content: \"Trang chủ / Cửa hàng\";\n    font-size: 14px;\n}\n\n/* CART TEXT */\n.site-header-cart .cart-contents {\n    font-size: 0;\n}\n.site-header-cart .cart-contents:after {\n    content: \"Giỏ hàng\";\n    font-size: 14px;\n}\n/* FIX NUT THEM VAO GIO BI MAT CHU */\nul.products li.product .button,\n.woocommerce ul.products li.product .button,\n.add_to_cart_button,\n.button.product_type_simple {\n    font-size: 14px !important;\n    line-height: 1.2 !important;\n    color: #fff !important;\n    text-indent: 0 !important;\n    overflow: visible !important;\n    white-space: nowrap !important;\n    min-width: 140px !important;\n    text-align: center !important;\n}\n\nul.products li.product .button::after,\n.woocommerce ul.products li.product .button::after,\n.add_to_cart_button::after,\n.button.product_type_simple::after {\n    content: none !important;\n}\n/* FIX NUT ADD TO CART -> THÊM VÀO GIỎ HÀNG */\nul.products li.product .button,\n.woocommerce ul.products li.product .button,\n.add_to_cart_button,\n.button.product_type_simple {\n    position: relative;\n    font-size: 0 !important;\n    min-width: 160px !important;\n    text-align: center !important;\n    color: transparent !important;\n}\n\nul.products li.product .button::before,\n.woocommerce ul.products li.product .button::before,\n.add_to_cart_button::before,\n.button.product_type_simple::before {\n    content: \"Thêm vào giỏ hàng\";\n    font-size: 14px;\n    line-height: 1.2;\n    color: #fff;\n    position: relative;\n    z-index: 2;\n}\n/* VIET HOA NUT VIEW CART */\n.added_to_cart.wc-forward {\n    position: relative;\n    font-size: 0 !important;\n    color: transparent !important;\n    min-width: 120px !important;\n    text-align: center !important;\n}\n\n.added_to_cart.wc-forward::before {\n    content: \"Xem giỏ hàng\";\n    font-size: 14px;\n    line-height: 1.2;\n    color: #fff;\n    position: relative;\n    z-index: 2;\n}\n.woocommerce-breadcrumb {\n    font-size: 0;\n}\n.woocommerce-breadcrumb:after {\n    content: \"Trang chủ / Cửa hàng\";\n    font-size: 14px;\n}\n/* ===== Thiện store - AI Chatbox Custom UI ===== */\n\n/* Nút bong bóng chat */\n.mwai-open-button,\n.mwai-chatbot-button,\n.mwai-trigger,\n.mwai-window .mwai-open-button {\n    width: 64px !important;\n    height: 64px !important;\n    border-radius: 50% !important;\n    background: #111111 !important;\n    color: #ffffff !important;\n    box-shadow: 0 12px 35px rgba(0, 0, 0, 0.22) !important;\n    border: 2px solid #ffffff !important;\n    transition: all 0.25s ease !important;\n}\n\n.mwai-open-button:hover,\n.mwai-chatbot-button:hover,\n.mwai-trigger:hover {\n    transform: translateY(-4px) scale(1.04) !important;\n    background: #d32f2f !important;\n    box-shadow: 0 16px 40px rgba(211, 47, 47, 0.35) !important;\n}\n\n/* Khung chatbot */\n.mwai-chatbot,\n.mwai-window,\n.mwai-chat {\n    border-radius: 22px !important;\n    overflow: hidden !important;\n    border: 1px solid #eeeeee !important;\n    box-shadow: 0 24px 70px rgba(0, 0, 0, 0.18) !important;\n    font-family: inherit !important;\n}\n\n/* Header chatbot */\n.mwai-header {\n    background: linear-gradient(135deg, #111111, #2a2a2a) !important;\n    color: #ffffff !important;\n    padding: 18px 20px !important;\n    border-bottom: none !important;\n}\n\n.mwai-header .mwai-title,\n.mwai-header h2,\n.mwai-header h3 {\n    color: #ffffff !important;\n    font-size: 17px !important;\n    font-weight: 700 !important;\n    letter-spacing: 0.2px !important;\n}\n\n/* Khu vực hội thoại */\n.mwai-conversation,\n.mwai-messages {\n    background: #fafafa !important;\n    padding: 18px !important;\n}\n\n/* Tin nhắn chung */\n.mwai-reply,\n.mwai-message {\n    margin-bottom: 12px !important;\n}\n\n/* Tin nhắn AI */\n.mwai-ai .mwai-text,\n.mwai-reply.mwai-ai,\n.mwai-message.mwai-ai {\n    background: #ffffff !important;\n    color: #222222 !important;\n    border: 1px solid #eeeeee !important;\n    border-radius: 16px 16px 16px 6px !important;\n    padding: 12px 14px !important;\n    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.04) !important;\n}\n\n/* Tin nhắn người dùng */\n.mwai-user .mwai-text,\n.mwai-reply.mwai-user,\n.mwai-message.mwai-user {\n    background: #111111 !important;\n    color: #ffffff !important;\n    border-radius: 16px 16px 6px 16px !important;\n    padding: 12px 14px !important;\n}\n\n/* Ô nhập tin nhắn */\n.mwai-input,\n.mwai-input textarea,\n.mwai-input input {\n    background: #ffffff !important;\n    border-top: 1px solid #eeeeee !important;\n}\n\n.mwai-input textarea,\n.mwai-input input[type=\"text\"] {\n    border: 1px solid #dddddd !important;\n    border-radius: 999px !important;\n    padding: 13px 48px 13px 16px !important;\n    font-size: 14px !important;\n    outline: none !important;\n    background: #ffffff !important;\n    color: #111111 !important;\n}\n\n.mwai-input textarea:focus,\n.mwai-input input[type=\"text\"]:focus {\n    border-color: #111111 !important;\n    box-shadow: 0 0 0 3px rgba(17, 17, 17, 0.08) !important;\n}\n\n/* Nút gửi */\n.mwai-input button,\n.mwai-send {\n    background: #111111 !important;\n    color: #ffffff !important;\n    border-radius: 999px !important;\n    border: none !important;\n    transition: all 0.2s ease !important;\n}\n\n.mwai-input button:hover,\n.mwai-send:hover {\n    background: #d32f2f !important;\n    transform: scale(1.04) !important;\n}\n\n/* Text nhỏ / powered by nếu có */\n.mwai-footer,\n.mwai-compliance,\n.mwai-powered {\n    font-size: 11px !important;\n    color: #999999 !important;\n    background: #ffffff !important;\n}\n\n/* Mobile */\n@media (max-width: 768px) {\n    .mwai-chatbot,\n    .mwai-window,\n    .mwai-chat {\n        width: calc(100vw - 24px) !important;\n        right: 12px !important;\n        left: 12px !important;\n        bottom: 90px !important;\n        border-radius: 20px !important;\n    }\n\n    .mwai-open-button,\n    .mwai-chatbot-button,\n    .mwai-trigger {\n        width: 58px !important;\n        height: 58px !important;\n        right: 18px !important;\n        bottom: 18px !important;\n    }\n}', 'storefront', '', 'inherit', 'closed', 'closed', '', '33-revision-v1', '', '', '2026-06-05 14:23:40', '2026-06-05 14:23:40', '', 33, 'http://localhost/thienhasagi/?p=67', 0, 'revision', '', 0),
(68, 1, '2026-06-05 14:25:26', '2026-06-05 14:25:26', '{\n    \"custom_css[storefront]\": {\n        \"value\": \"/* B\\u1ecf sidebar WooCommerce */\\n#secondary {\\n    display: none;\\n}\\n\\n/* Cho n\\u1ed9i dung full width */\\n#primary {\\n    width: 100% !important;\\n}\\n/* ===== THIEN STORE - COMMERCIAL LOOK ===== */\\n\\n/* 1) \\u1ea8n sidebar \\u0111\\u1ec3 shop full width */\\n#secondary {\\n    display: none !important;\\n}\\n\\n#primary,\\n.content-area {\\n    width: 100% !important;\\n    float: none !important;\\n    margin: 0 !important;\\n}\\n\\n/* 2) T\\u1ed5ng th\\u1ec3 trang g\\u1ecdn h\\u01a1n */\\nbody {\\n    background: #f7f7f7;\\n}\\n\\n.site {\\n    background: #ffffff;\\n}\\n\\n.site-main {\\n    padding-top: 10px;\\n    padding-bottom: 30px;\\n}\\n\\n/* 3) Header g\\u1ecdn, s\\u1ea1ch, gi\\u1ed1ng web b\\u00e1n h\\u00e0ng h\\u01a1n */\\n.site-header {\\n    background: #ffffff !important;\\n    border-bottom: 1px solid #e5e5e5;\\n    padding-top: 16px;\\n    padding-bottom: 10px;\\n    margin-bottom: 24px;\\n}\\n\\n.site-branding {\\n    margin-bottom: 10px !important;\\n}\\n\\n.site-title a {\\n    font-size: 34px !important;\\n    font-weight: 700 !important;\\n    color: #111 !important;\\n    text-decoration: none !important;\\n}\\n\\n.site-description {\\n    display: none !important;\\n}\\n\\n/* 4) Menu \\u0111\\u1eb9p v\\u00e0 g\\u1ecdn h\\u01a1n */\\n.main-navigation ul.menu > li > a,\\n.main-navigation ul.nav-menu > li > a {\\n    font-weight: 600;\\n    font-size: 15px;\\n    color: #222 !important;\\n    padding: 12px 14px !important;\\n}\\n\\n.main-navigation ul.menu > li > a:hover,\\n.main-navigation ul.nav-menu > li > a:hover {\\n    color: #c62828 !important;\\n}\\n\\n/* 5) \\u00d4 t\\u00ecm ki\\u1ebfm v\\u00e0 gi\\u1ecf h\\u00e0ng g\\u1ecdn h\\u01a1n */\\n.site-search .widget_product_search,\\n.site-search .widget_search {\\n    margin-bottom: 0 !important;\\n}\\n\\n.site-search input[type=\\\"search\\\"] {\\n    border: 1px solid #ddd;\\n    border-radius: 8px;\\n    background: #fff;\\n}\\n\\n.site-header-cart .cart-contents {\\n    font-weight: 600;\\n}\\n\\n/* 6) Ti\\u00eau \\u0111\\u1ec1 trang */\\n.page-title,\\n.woocommerce-products-header__title.page-title {\\n    font-size: 42px !important;\\n    font-weight: 700 !important;\\n    color: #111;\\n    margin-bottom: 24px !important;\\n}\\n\\n/* 7) Khu v\\u1ef1c shop tho\\u00e1ng v\\u00e0 gi\\u1ed1ng e-commerce h\\u01a1n */\\n.storefront-breadcrumb {\\n    margin-bottom: 20px !important;\\n}\\n\\n.woocommerce-result-count,\\n.woocommerce-ordering {\\n    margin-bottom: 24px !important;\\n}\\n\\n/* 8) Card s\\u1ea3n ph\\u1ea9m \\u0111\\u1eb9p h\\u01a1n */\\nul.products li.product,\\n.woocommerce-page ul.products li.product {\\n    background: #fff;\\n    border: 1px solid #ececec;\\n    border-radius: 14px;\\n    padding: 16px 16px 20px;\\n    box-shadow: 0 6px 18px rgba(0,0,0,0.04);\\n    transition: all 0.2s ease;\\n}\\n\\nul.products li.product:hover,\\n.woocommerce-page ul.products li.product:hover {\\n    transform: translateY(-4px);\\n    box-shadow: 0 10px 24px rgba(0,0,0,0.08);\\n}\\n\\n/* 9) \\u1ea2nh s\\u1ea3n ph\\u1ea9m */\\nul.products li.product img,\\n.woocommerce-page ul.products li.product img {\\n    border-radius: 10px;\\n    margin-bottom: 14px !important;\\n}\\n\\n/* 10) T\\u00ean s\\u1ea3n ph\\u1ea9m */\\nul.products li.product h2,\\nul.products li.product .woocommerce-loop-product__title,\\n.woocommerce-page ul.products li.product h2,\\n.woocommerce-page ul.products li.product .woocommerce-loop-product__title {\\n    font-size: 18px !important;\\n    font-weight: 600 !important;\\n    color: #111 !important;\\n    min-height: 48px;\\n    margin-bottom: 10px !important;\\n}\\n\\n/* 11) Gi\\u00e1 s\\u1ea3n ph\\u1ea9m */\\n.price {\\n    color: #c62828 !important;\\n    font-weight: 700 !important;\\n    font-size: 18px !important;\\n}\\n\\n.price del {\\n    color: #999 !important;\\n    font-size: 14px !important;\\n}\\n\\n.price ins {\\n    background: transparent !important;\\n}\\n\\n/* 12) N\\u00fat Add to cart nh\\u00ecn th\\u01b0\\u01a1ng m\\u1ea1i h\\u01a1n */\\n.button,\\nbutton,\\ninput[type=\\\"button\\\"],\\ninput[type=\\\"submit\\\"],\\na.button,\\n.added_to_cart,\\n.single_add_to_cart_button,\\n.checkout-button,\\n.wc-forward {\\n    background: #111 !important;\\n    color: #fff !important;\\n    border-radius: 10px !important;\\n    border: none !important;\\n    padding: 12px 18px !important;\\n    font-weight: 600 !important;\\n    transition: all 0.2s ease;\\n}\\n\\n.button:hover,\\nbutton:hover,\\ninput[type=\\\"button\\\"]:hover,\\ninput[type=\\\"submit\\\"]:hover,\\na.button:hover,\\n.added_to_cart:hover,\\n.single_add_to_cart_button:hover,\\n.checkout-button:hover,\\n.wc-forward:hover {\\n    background: #c62828 !important;\\n    color: #fff !important;\\n}\\n\\n/* 13) Sale badge \\u0111\\u1eb9p h\\u01a1n */\\n.onsale {\\n    background: #c62828 !important;\\n    color: #fff !important;\\n    border-radius: 999px !important;\\n    padding: 6px 10px !important;\\n    font-size: 12px !important;\\n    font-weight: 700 !important;\\n    min-width: auto !important;\\n    min-height: auto !important;\\n    line-height: 1.2 !important;\\n    box-shadow: none !important;\\n}\\n\\n/* 14) Cart / Checkout box \\u0111\\u1eb9p h\\u01a1n */\\n.woocommerce-cart-form,\\n.cart-collaterals,\\n.woocommerce-checkout-review-order,\\n.woocommerce-billing-fields,\\n.woocommerce-additional-fields,\\n.woocommerce-form-coupon,\\n.woocommerce-MyAccount-content,\\n.woocommerce-Address,\\n.woocommerce-orders-table {\\n    background: #fff;\\n    border: 1px solid #ececec;\\n    border-radius: 14px;\\n    padding: 20px;\\n    box-shadow: 0 6px 18px rgba(0,0,0,0.04);\\n}\\n\\n/* 15) Form input \\u0111\\u1eb9p h\\u01a1n */\\ninput[type=\\\"text\\\"],\\ninput[type=\\\"email\\\"],\\ninput[type=\\\"tel\\\"],\\ninput[type=\\\"password\\\"],\\ninput[type=\\\"search\\\"],\\ntextarea,\\nselect {\\n    border: 1px solid #dcdcdc !important;\\n    border-radius: 10px !important;\\n    background: #fff !important;\\n    padding: 12px 14px !important;\\n}\\n\\n/* 16) Footer nh\\u00ecn nh\\u01b0 doanh nghi\\u1ec7p h\\u01a1n */\\n.site-footer {\\n    background: #111 !important;\\n    color: #eee !important;\\n    padding-top: 40px !important;\\n    padding-bottom: 20px !important;\\n    margin-top: 40px !important;\\n}\\n\\n.site-footer,\\n.site-footer a,\\n.site-footer .widget-title {\\n    color: #eee !important;\\n}\\n\\n.site-footer a:hover {\\n    color: #ffb3b3 !important;\\n}\\n\\n.site-footer .widget {\\n    margin-bottom: 20px;\\n}\\n\\n.site-footer .widget-title {\\n    font-size: 18px !important;\\n    font-weight: 700 !important;\\n    margin-bottom: 14px !important;\\n}\\n\\n.site-info {\\n    border-top: 1px solid rgba(255,255,255,0.12);\\n    padding-top: 14px;\\n    margin-top: 20px;\\n    text-align: center;\\n    color: #ccc !important;\\n}\\n\\n/* 17) \\u1ea8n m\\u1ed9t s\\u1ed1 chi ti\\u1ebft th\\u1eeba n\\u1ebfu c\\u00f3 */\\n.storefront-handheld-footer-bar {\\n    display: none;\\n}\\n\\n/* 18) Responsive */\\n@media (max-width: 768px) {\\n    .site-title a {\\n        font-size: 28px !important;\\n    }\\n\\n    .page-title,\\n    .woocommerce-products-header__title.page-title {\\n        font-size: 32px !important;\\n    }\\n\\n    ul.products li.product,\\n    .woocommerce-page ul.products li.product {\\n        padding: 12px;\\n    }\\n}\\n/* FIX FOOTER TEXT COLOR */\\n.site-footer,\\n.site-footer p,\\n.site-footer h4,\\n.site-footer span,\\n.site-footer a {\\n    color: #ffffff !important;\\n}\\n\\n.site-footer a:hover {\\n    color: #ffb3b3 !important;\\n}\\n/* ===== VIET HOA WOOCOMMERCE ===== */\\n\\n/* SHOP TITLE */\\n.woocommerce-products-header__title.page-title {\\n    font-size: 0;\\n}\\n\\n/* SORTING */\\n.woocommerce-ordering select {\\n    font-size: 0;\\n}\\n.woocommerce-ordering:before {\\n    content: \\\"S\\u1e